import React, { useMemo, useState } from 'react';
import {
  useReactTable,
  getCoreRowModel,
  getSortedRowModel,
  getGroupedRowModel,
  flexRender
} from '@tanstack/react-table';
import './DataTable.css';

const DataTable = ({ data = [], type, title }) => {
  const [sorting, setSorting] = useState([{ id: 'name', desc: false }]);
  const [grouping] = useState(type === 'students' ? ['subject'] : ['subject']);

  const subjectMap = {
    subject1: 'Comp.arch',
    subject2: 'TRPO',
    subject3: 'Calc.math',
    subject4: 'Calc.math',
    date1: 'Дата 1',
    date2: 'Дата 2',
    date3: 'Дата 3',
    date4: 'Дата 4',
    date5: 'Дата 5'
  };

  const normalizedData = useMemo(() => {
    if (!Array.isArray(data) || data.length === 0) {
      return [];
    }

    if (type === 'students') {
      return data.flatMap((student) => {
        const subjects = ['subject1', 'subject2', 'subject3', 'subject4'];
        const grades = subjects.map((subject) => Number(student[subject]) || 0);
        const average = grades.reduce((sum, value) => sum + value, 0) / (grades.length || 1);

        return subjects.map((subject) => ({
          studentId: student.id ?? 0,
          name: student.name ?? '',
          group: student.group ?? '',
          subject: subjectMap[subject] || subject,
          date: '',
          score: Number(student[subject]) || 0,
          rating: Number(average.toFixed(2))
        }));
      });
    }

    if (type === 'attendance') {
      return data.flatMap((student) => {
        const dates = ['date1', 'date2', 'date3', 'date4', 'date5'];
        const presentCount = dates.reduce((sum, dateKey) => {
          const val = student[dateKey];
          const ok = val === 'P' || val === 'p' || val === 'Да' || val === true || Number(val) === 1;
          return sum + (ok ? 1 : 0);
        }, 0);

        const ratio = Math.round((presentCount / (dates.length || 1)) * 100);

        return dates.map((dateKey) => ({
          studentId: student.id ?? 0,
          name: student.name ?? '',
          group: student.group ?? '',
          subject: subjectMap[dateKey] || dateKey,
          date: student[dateKey] ?? '',
          score: student[dateKey],
          rating: ratio
        }));
      });
    }

    // fallback: все поля если нет специального типа
    return data.map((item, index) => ({
      studentId: item.id ?? index + 1,
      name: item.name ?? '',
      group: item.group ?? '',
      subject: item.subject ?? '',
      date: item.date ?? '',
      score: item.score ?? '',
      rating: item.rating ?? 0
    }));
  }, [data, type]);

  const maxValues = useMemo(() => {
    const max = { score: Number.NEGATIVE_INFINITY, rating: Number.NEGATIVE_INFINITY };

    for (const row of normalizedData) {
      const score = Number(row.score);
      const rating = Number(row.rating);
      if (!Number.isNaN(score) && score > max.score) max.score = score;
      if (!Number.isNaN(rating) && rating > max.rating) max.rating = rating;
    }

    return max;
  }, [normalizedData]);

  const columns = useMemo(() => {
    const base = [
      {
        header: '№',
        accessorKey: 'studentId',
        enableSorting: true,
        cell: (info) => info.getValue(),
        size: 50
      },
      {
        header: 'ФИО',
        accessorKey: 'name',
        enableSorting: true
      },
      {
        header: 'Группа',
        accessorKey: 'group',
        enableSorting: true
      },
      {
        header: type === 'attendance' ? 'Дата' : 'Предмет',
        accessorKey: 'subject',
        enableGrouping: true,
        enableSorting: true
      },
      {
        header: type === 'attendance' ? 'Посещение' : 'Оценка',
        accessorKey: 'score',
        enableSorting: true,
        cell: (info) => info.getValue()
      },
      {
        header: 'Общий рейтинг (%)',
        accessorKey: 'rating',
        enableSorting: true,
        cell: (info) => info.getValue()
      }
    ];

    return [
      {
        header: 'Студент',
        columns: base.slice(0, 3)
      },
      {
        header: type === 'attendance' ? 'Посещаемость' : 'Успеваемость',
        columns: base.slice(3)
      }
    ];
  }, [type]);

  const table = useReactTable({
    data: normalizedData,
    columns,
    state: {
      sorting,
      grouping
    },
    onSortingChange: setSorting,
    onGroupingChange: () => {},
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getGroupedRowModel: getGroupedRowModel(),
    enableGrouping: true,
    initialState: {
      grouping
    }
  });

  return (
    <div className="contfor-table">
      <div className="pfp-block-inner">
        <h2>{title}</h2>
        <table className="tanstack-table" style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            {table.getHeaderGroups().map((headerGroup) => (
              <tr key={headerGroup.id}>
                {headerGroup.headers.map((header) => (
                  <th
                    key={header.id}
                    colSpan={header.colSpan}
                    style={{
                      border: '1px solid #444',
                      padding: '8px',
                      background: '#5E3E9F',
                      color: '#fff',
                      textAlign: 'left',
                      cursor: header.column.getCanSort() ? 'pointer' : 'default'
                    }}
                    onClick={header.column.getToggleSortingHandler()}
                  >
                    {flexRender(header.column.columnDef.header, header.getContext())}
                    {{ asc: ' 🔼', desc: ' 🔽' }[header.column.getIsSorted()] ?? null}
                  </th>
                ))}
              </tr>
            ))}
          </thead>
          <tbody>
            {table.getRowModel().rows.map((row) => {
              if (row.getIsGrouped()) {
                return (
                  <tr key={row.id} className="group-row" style={{ background: '#2e2e2e', color: '#fff' }}>
                    <td colSpan={row.getVisibleCells().length} style={{ padding: '8px', border: '1px solid #444' }}>
                      {row.getValue('subject')} ({row.subRows.length})
                    </td>
                  </tr>
                );
              }

              return (
                <tr key={row.id} style={{ borderBottom: '1px solid #555' }}>
                  {row.getVisibleCells().map((cell) => {
                    const columnId = cell.column.id;
                    const value = cell.getValue();
                    const isMax =
                      (columnId === 'score' && Number(value) === maxValues.score) ||
                      (columnId === 'rating' && Number(value) === maxValues.rating);

                    return (
                      <td
                        key={cell.id}
                        style={{
                          border: '1px solid #444',
                          padding: '8px',
                          background: isMax ? '#ffe58f' : '#1f1f1f',
                          color: '#f7f7f7'
                        }}
                      >
                        {flexRender(cell.column.columnDef.cell, cell.getContext())}
                      </td>
                    );
                  })}
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default DataTable;